import React, { useEffect, useState } from "react";
import { FiMessageCircle, FiX } from "react-icons/fi";

const dummyChats = [
  {
    id: 1,
    user: "What should I eat before my long run?",
    coach: "Go for something high-carb and easy to digest, like toast with peanut butter and a banana.",
  },
  {
    id: 2,
    user: "How do I avoid shin splints?",
    coach: "Make sure you're not ramping up mileage too fast. Add strength work and check your shoes.",
  },
  {
    id: 3,
    user: "Should I run if I'm sore from lifting?",
    coach: "Light running is fine, but listen to your body. Prioritize recovery if you're very sore.",
  },
  // Add 2–7 more
];

export default function ChatSidebar() {
    const [open, setOpen] = useState(false);

    const toggleSidebar = () => setOpen(!open);

    useEffect(() => {
      const handleKeyDown = (e) => {
        if ((e.metaKey || e.ctrlKey) && e.key.toLowerCase() === "o") {
          e.preventDefault();
          toggleSidebar();
        }
      };
      window.addEventListener("keydown", handleKeyDown);
      return () => window.removeEventListener("keydown", handleKeyDown);
    }, []);

    return (
      <>
        {/* Toggle Button */}
        <button
          onClick={toggleSidebar}
          className="fixed top-4 right-4 z-50 bg-white border rounded-full p-2 shadow hover:bg-gray-100"
        >
          <FiMessageCircle size={20} />
        </button>

        {/* Sidebar */}
        <div
          className={`fixed top-0 right-0 h-full w-96 bg-[#f9f9f9] z-40 shadow-lg transform transition-transform duration-300 ${
            open ? "translate-x-0" : "translate-x-full"
          }`}
        >
          <div className="flex justify-between items-center px-4 py-3 shadow-sm">
            <h2 className="text-lg font-semibold">Chat History</h2>
            <button onClick={toggleSidebar}>
              <FiX size={22} />
            </button>
          </div>

          <div className="overflow-y-auto p-4 space-y-4">
            {dummyChats.map((chat) => (
              <div
                key={chat.id}
                className="bg-white rounded-2xl p-4 shadow-sm"
              >
                <div className="text-sm text-gray-500 font-medium mb-1">You</div>
                <p className="mb-3">{chat.user}</p>
                <div className="text-sm text-gray-500 font-medium mb-1">Coach</div>
                <p>{chat.coach}</p>
              </div>
            ))}
          </div>
        </div>
      </>
    );
  }
